// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = 3000;
const db = new Database("data.db");

db.pragma("journal_mode = WAL");
db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

app.use(express.json());

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  created_at: string;
  updated_at: string;
};

const listBookmarksStatement = db.prepare("SELECT * FROM bookmarks ORDER BY id ASC");

const getBookmarkStatement = db.prepare("SELECT * FROM bookmarks WHERE id = ?");

const createBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, created_at, updated_at)
  VALUES (@url, @title, @description, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const listBookmarks = (): Bookmark[] =>
  listBookmarksStatement.all() as Bookmark[];

const getBookmark = (id: number): Bookmark | undefined =>
  getBookmarkStatement.get(id) as Bookmark | undefined;

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/bookmarks", (req, res) => {
  const { url, title, description } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
  };

  if (!isNonEmptyString(url)) {
    res.status(400).json({ error: "url is required" });
    return;
  }

  if (!isNonEmptyString(title)) {
    res.status(400).json({ error: "title is required" });
    return;
  }

  const now = new Date().toISOString();
  const result = createBookmark.run({
    url: url.trim(),
    title: title.trim(),
    description: typeof description === "string" ? description : null,
    created_at: now,
    updated_at: now,
  });

  const bookmark = getBookmark(Number(result.lastInsertRowid));
  res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  res.status(200).json(listBookmarks());
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);
  const bookmark = id === null ? undefined : getBookmark(id);

  if (!bookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const currentBookmark = getBookmark(id);

  if (!currentBookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const { url, title, description } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
  };

  if (url !== undefined && !isNonEmptyString(url)) {
    res.status(400).json({ error: "url must be a non-empty string" });
    return;
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    res.status(400).json({ error: "title must be a non-empty string" });
    return;
  }

  updateBookmark.run({
    id,
    url: isNonEmptyString(url) ? url.trim() : currentBookmark.url,
    title: isNonEmptyString(title) ? title.trim() : currentBookmark.title,
    description:
      description === undefined
        ? currentBookmark.description
        : typeof description === "string"
          ? description
          : null,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getBookmark(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);
  const result = id === null ? { changes: 0 } : deleteBookmark.run(id);

  if (result.changes === 0) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

